library(spatstat)
library(ggplot2)
library(ggforce)

set.seed(1)

# ---- 1. INITIALISATION ----
w <- owin(c(0,1), c(0,1))
resolution <- 1000

# Points initiaux (Feux Jour 1)
hotspot <- function(x, y) { 6 * x + 4 * y }
pts_actuels <- rpoispp(hotspot, win = w)

# Fonction d'intensité pour les combustibles régénérés (multipliée par 100 selon votre code)
combustibles_func <- function(x, y) { 5 * (100 + 100 * x + 100 * y^3 + 100 * y) }

# CORRECTION : Définition propre et isolée de la fonction des rayons
generer_rayons_func <- function(x, y) {
  return(floor(1 + 5 * (cos(x * pi - 0.5) * sin(y * pi - 0.5) + 1) / 2))
}

# ---- VISUALISATION DE LA FONCTION DES RAYONS (Exécutée immédiatement) ----
grille <- expand.grid(
  x = seq(0, 1, length.out = 200),
  y = seq(0, 1, length.out = 200)
)
grille$rayon_brut <- generer_rayons_func(grille$x, grille$y)

p_fonction <- ggplot(grille, aes(x = x, y = y, fill = rayon_brut)) +
  geom_raster(interpolate = TRUE) +
  scale_fill_viridis_c(option = "plasma", name = "Rayon brut\n(1 à 6)") +
  labs(
    title = "Intensité spatiale de la fonction des rayons",
    subtitle = "Visualisation des variations du rayon brut f(x,y) sur le carré [0,1]",
    x = "x", y = "y"
  ) +
  coord_fixed(xlim = c(0, 1), ylim = c(0, 1), expand = FALSE) +
  theme_minimal()

print(p_fonction) # Affiche la carte d'intensité des rayons
